                  "list": [{ "descriptor": { "code": "eligibilityText", "name": "eligibility Text" }, "value": "Economic eligibility: Nature of Job: = Farmer; Sources of irrigation available for the land ?: = Yes; Do you or any of your family members own any land?: = Yes - for agriculture; Present Occupational Status: = Working; Present Occupational Status: = Student and Working\nDemographic eligibility: Which State/UT are you presently residing ?: = Uttar Pradesh; What is your age?: >= 18", "display": true }]
                }
